import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        s = next(it)
        n = len(s)
        if n % 2 == 1:
            out.append('-1')
            continue
        zeros = s.count('0')
        if zeros == n // 2:
            out.append('0')
        elif '0' in s and '1' in s:
            out.append(str(abs(zeros - n // 2)))
        else:
            out.append('-1')
    sys.stdout.write('
'.join(out))

if __name__ == "__main__":
    solve()

